+pub unsafe fn sys_utimensat(
+    dirfd: i32,
+    pathname: *const u8,
+    times: *const u8,
+    flags: i32,
+) -> Result<(), i32> {
+    let ret = unsafe {
+        raw::syscall4(
+            SYS_UTIMENSAT,
+            dirfd as usize,
+            pathname as usize,
+            times as usize,
+            flags as usize,
+        )
+    };
+    syscall_result(ret).map(|_| ())
+}
